.darma-loader-loaders-css-26 {
      display: inline-flex;
      align-items: center;
      justify-content: center;
      gap: 4px;
      height: 40px;
    }
    .darma-loader-loaders-css-26 i {
      display: block;
      width: 6px;
      height: 40px;
      border-radius: 999px;
      background: linear-gradient(180deg, var(--loader-color, #6366f1), var(--loader-secondary-color, #a5b4fc));
      transform-origin: center bottom;
      animation: darma-loader-loaders-css-26-barPulse 0.95s ease-in-out infinite;
    }
    .darma-loader-loaders-css-26 i:nth-child(1) { animation-delay: 0.00s; }
.darma-loader-loaders-css-26 i:nth-child(2) { animation-delay: 0.09s; }
.darma-loader-loaders-css-26 i:nth-child(3) { animation-delay: 0.18s; }
.darma-loader-loaders-css-26 i:nth-child(4) { animation-delay: 0.27s; }
.darma-loader-loaders-css-26 i:nth-child(5) { animation-delay: 0.36s; }
    @keyframes darma-loader-loaders-css-26-barPulse { 0%, 100% { transform: translateY(0) scaleY(.55); opacity: .45; } 50% { transform: translateY(-7px) scaleY(1); opacity: 1; } }

